  private void UpdateWarningLabel(PowerMonitoringFlags flags)
  {
    if (flags == PowerMonitoringFlags.None)
    {
      ((Control) this.SystemWarningPanel).Visible = false;
    }
    else
    {
      FormattedMessage formattedMessage = new FormattedMessage();
      if ((flags & PowerMonitoringFlags.RoguePowerConsumer) != PowerMonitoringFlags.None)
      {
        this.SystemWarningPanel.PanelOverride = (StyleBox) new StyleBoxFlat()
        {
          BackgroundColor = Color.Red,
          BorderColor = Color.DarkRed,
          BorderThickness = new Thickness(2f)
        };
        formattedMessage.AddMarkupOrThrow(Loc.GetString("power-monitoring-window-rogue-power-consumer"));
        ((Control) this.SystemWarningPanel).Visible = true;
      }
      else if ((flags & PowerMonitoringFlags.PowerNetAbnormalities) != PowerMonitoringFlags.None)
      {
        this.SystemWarningPanel.PanelOverride = (StyleBox) new StyleBoxFlat()
        {
          BackgroundColor = Color.Orange,
          BorderColor = Color.DarkOrange,
          BorderThickness = new Thickness(2f)
        };
        formattedMessage.AddMarkupOrThrow(Loc.GetString("power-monitoring-window-power-net-abnormalities"));
        ((Control) this.SystemWarningPanel).Visible = true;
      }
      this.SystemWarningLabel.SetMessage(formattedMessage, new Color?());
    }
  }

  private void SwitchTabsBasedOnPowerMonitoringConsoleGroup(PowerMonitoringConsoleGroup group)
  {
    switch (group)
    {
      case PowerMonitoringConsoleGroup.Generator:
        this.MasterTabContainer.CurrentTab = 0;
        break;
      case PowerMonitoringConsoleGroup.SMES:
        this.MasterTabContainer.CurrentTab = 1;
        break;
      case PowerMonitoringConsoleGroup.Substation:
        this.MasterTabContainer.CurrentTab = 2;
        break;
      case PowerMonitoringConsoleGroup.APC:
        this.MasterTabContainer.CurrentTab = 3;
        break;
    }
  }

  private PowerMonitoringConsoleGroup GetCurrentPowerMonitoringConsoleGroup()
